+// addr builds a netlink.Addr suitable for use in filterAddrsExcept tests.
+func addr(ip string, mask int, linkIndex int, label string) netlink.Addr {
+	parsed := net.ParseIP(ip)
+	bits := 32
+	if parsed.To4() == nil {
+		bits = 128
+	}
+	return netlink.Addr{
+		IPNet:     &net.IPNet{IP: parsed, Mask: net.CIDRMask(mask, bits)},
+		Label:     label,
+		LinkIndex: linkIndex,
+	}
+}
+
+func collectIPs(addrs []net.Addr) []string {
+	out := make([]string, 0, len(addrs))
+	for _, a := range addrs {
+		ipnet, ok := a.(*net.IPNet)
+		if !ok {
+			continue
+		}
+		out = append(out, ipnet.IP.String())
+	}
+	return out
+}
+
+func containsAll(have []string, want ...string) bool {
+	index := make(map[string]struct{}, len(have))
+	for _, h := range have {
+		index[h] = struct{}{}
+	}
+	for _, w := range want {
+		if _, ok := index[w]; !ok {
+			return false
+		}
+	}
+	return true
+}
+
+func containsAny(have []string, candidates ...string) bool {
+	index := make(map[string]struct{}, len(have))
+	for _, h := range have {
+		index[h] = struct{}{}
+	}
+	for _, c := range candidates {
+		if _, ok := index[c]; ok {
+			return true
+		}
+	}
+	return false
+}
+
+func TestFilterAddrsExceptByLinkIndex(t *testing.T) {
+	// dev=kube-ipvs0 with ifindex=10 holds many ClusterIPs.
+	// eth0 with ifindex=2 holds the node IP.
