+		addr("10.233.0.1", 32, 10, "kube-ipvs0"),
+		addr("10.233.0.2", 32, 10, "kube-ipvs0"),
+		addr("10.233.0.3", 32, 10, "kube-ipvs0"),
+		addr("fd00::1", 128, 2, ""), // IPv6 has no Label, must be matched by LinkIndex semantics
